db.revokeRolesFromUser('reporting-user', [{ role: 'rawRead', db: 'appdb' }]);
// Grant the reportingRole (appdb.reports access only)
db.grantRolesToUser('reporting-user', [{ role: 'reportingRole', db: 'appdb' }]);
// Verify
var user = db.getUser('reporting-user');
print('Updated roles for reporting-user:');
printjson(user.roles);
" 2>&1

